import { GoogleLogin } from "@react-oauth/google";
import { jwtDecode } from "jwt-decode";
import React, { useState, useContext } from "react";
import { Link, useNavigate } from "react-router-dom";
import { AuthContext } from "../context/AuthContext";

const Login = () => {
  const [activeTab, setActiveTab] = useState("login");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [name, setName] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const navigate = useNavigate();

  const { login } = useContext(AuthContext);

  // 🔹 Xử lý login bằng Google
  const handleGoogleLogin = async (credentialResponse) => {
    try {
      const decoded = jwtDecode(credentialResponse.credential);
      console.log("Google decoded:", decoded);

      const res = await fetch("http://localhost:5000/api/auth/google", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          email: decoded.email,
          name: decoded.name,
          googleId: decoded.sub,
          picture: decoded.picture,
        }),
      });

      const data = await res.json();
      if (data.success) {
        localStorage.setItem("userInfo", JSON.stringify(data.user));
        localStorage.setItem("token", data.token);

        if (data.user.role === "admin") navigate("/admin");
        else navigate("/");
      } else {
        setError(data.message || "Đăng nhập Google thất bại!");
      }
    } catch (err) {
      console.error(err);
      setError("Không thể đăng nhập bằng Google.");
    }
  };

  // 🔹 Xử lý login thường
  const handleLogin = async (e) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    try {
      const result = await login(email, password);
      if (result?.success) {
        localStorage.setItem("userInfo", JSON.stringify(result.user));
        localStorage.setItem("token", result.token);

        if (result.user.role === "admin") navigate("/admin");
        else navigate("/");
      } else setError(result?.message || "Sai thông tin đăng nhập!");
    } catch {
      setError("Lỗi đăng nhập!");
    }
    setLoading(false);
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#faf8f6] px-4 py-10">
      <div className="w-full max-w-md bg-white shadow-lg rounded-2xl border border-[#f2e4e0] p-8">
        <h2 className="text-center text-2xl font-semibold text-[#e06c7f] mb-6">
          {activeTab === "login" ? "🌸 Đăng nhập" : "🌷 Đăng ký"}
        </h2>

        {error && (
          <div className="bg-red-100 text-red-700 p-3 rounded-lg mb-4 text-center">
            ⚠️ {error}
          </div>
        )}

        {activeTab === "login" ? (
          <form onSubmit={handleLogin}>
            <input
              type="email"
              placeholder="Email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full mb-3 p-3 border border-gray-300 rounded-lg"
            />
            <div className="relative mb-6">
              <input
                type={showPassword ? "text" : "password"}
                placeholder="Mật khẩu"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full p-3 pr-10 border border-gray-300 rounded-lg"
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                className="absolute right-3 top-3 text-gray-500"
              >
                {showPassword ? "🙈" : "👁️"}
              </button>
            </div>

            <button
              type="submit"
              className="w-full bg-[#e06c7f] text-white py-3 rounded-lg font-medium hover:bg-[#d35c70] transition"
            >
              {loading ? "Đang đăng nhập..." : "Đăng nhập"}
            </button>

            {/* --- hoặc đăng nhập bằng Google --- */}
            <div className="flex items-center my-4">
              <div className="flex-grow h-px bg-gray-300"></div>
              <span className="px-3 text-gray-500 text-sm">hoặc</span>
              <div className="flex-grow h-px bg-gray-300"></div>
            </div>

            <div className="flex justify-center">
              <GoogleLogin
                onSuccess={handleGoogleLogin}
                onError={() => setError("Đăng nhập Google thất bại!")}
              />
            </div>
          </form>
        ) : (
          <div>Form đăng ký (bạn có thể giữ nguyên phần cũ)</div>
        )}
      </div>
    </div>
  );
};

export default Login;
